    ]
  }
}","language":"json","filename":"config.json","showCopy":"true","className":""},"children":[]},{"id":"1e9faa1a-ff04-4e6b-a426-b0a44e7da76f","component":"Divider","data":{"variant":"spacer","size":"md","label":"","className":""},"children":[]},{"id":"1a9d16c7-c936-44cf-a275-c45ee8bbd1b8","component":"Text","data":{"content":"First, we have the 2 keys, "key" and "config", the key must be unique, otherwise silent overrides may occur. Then there is the config object, this is the actual data you want to be configurable. You must also specify a component to render the configuration, and register that component. The values you can see in the code block above, are the DEFAULTS, your component must accept defaults, and error gracefully","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"a80719a4-5bbd-49f3-83d4-4546e9e91c48","component":"Text","data":{"content":"The configuration you've created can then be picked up by the application, and pulled into the users build/config.json. ","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"148a669d-d91e-4194-8d7f-b36efbee8257","component":"Alert","data":{"variant":"danger","title":"Never add private keys here","message":"Remember, this will end up in public hosted GitHub pages, or on static servers with a publicly accessible config. Public keys are fine, never write anything sensitive in here.","showIcon":"true","className":""},"children":[]},{"id":"e129bae7-bcc0-4c3a-a1fc-ad595054d1eb","component":"Divider","data":{"variant":"spacer","size":"sm","label":"","className":""},"children":[]},{"id":"fb0113a2-5a61-4ff1-812e-60c4e7424050","component":"Text","data":{"content":"Once you've taken these steps and restarted your server instance, the configuration editor you created should be immediately visible in your site settings.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"bae89aa9-e19d-4203-8b97-808f1bda066b","component":"Text","data":{"content":"The next step is to then use the configuration in your component.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"552bc78a-e795-48dd-b151-6a5d80dda966","component":"CodeBlock","data":{"code":"import React from "react";
import { useModuleConfig } from "@config";
import componentConfig from "./config.json";

/**
 * Define the expected configuration structure.
 * Passing this type into `useModuleConfig` gives us:
 *  - IDE autocomplete
 *  - compile-time safety
 *  - self-documenting configuration
 */
type HeaderConfig = {
  component: string;
  siteTitle: string;
  links: {
    to: string;
    label?: string;
    icon?: string;
  }[];
};

/**
 * Example configurable component.
 *
 * `useModuleConfig` accepts a generic type parameter describing
 * the structure of the configuration object. The hook will then
 * merge the user's site configuration with the defaults defined
 * in this module's `config.json`.
 */
export const Header: React.FC = () => {
  const config = useModuleConfig<HeaderConfig>(
    componentConfig.key,
    componentConfig.config
  );

  /**
   * Because we passed `HeaderConfig` as the generic type,
   * `config` is now fully typed and IDEs will provide
   * autocomplete for all configuration fields.
   */

  return (
    <header>
      <h1>{config.siteTitle}</h1>

      <nav>
        {config.links.map((link, index) => (
          <a key={index} href={link.to}>
            {link.icon && <i className={link.icon} />}
            {link.label}
          </a>
        ))}
      </nav>
    </header>
  );
};

registerComponent({
  name: "CustomHeader",
  defaults: componentConfig.config,
  component: Header as React.FC<CodefolioProps<HeaderConfig>>
});","language":"tsx","filename":"index.tsx","showCopy":"true","className":""},"children":[]}]
